### Conv2D variant

Named conv ops (`linalg.conv_2d_nhwc_hwcf`, `linalg.depthwise_conv_2d_*`)
cannot be vectorized directly - `transform.structured.vectorize_children_and_apply_patterns`
will fail with "failed to apply" because the vectorizer does not know how
to lower the window-reduction semantics in one shot. IREE's own
`CPUConvTileAndDecomposeExpert` pipeline decomposes the conv to
1x1 im2col-style matmul-like ops first; a hand-authored strategy must do

// iter_1: widen OW inner tile from 8 to 16 to double filter-weight reuse per
// broadcast. Baseline has 15 flw : 24 vfmacc per inner step. With OW strip=16,
// each broadcast feeds 16 vfmacc instead of 8, so the flw:fma ratio drops
// from ~0.62 toward ~0.31 and total dynamic instruction count falls.
//
// Register budget at LMUL=m1 (OF=32 -> one vreg per output slab):
//   - 16 accumulator vregs (v_acc_0 .. v_acc_15)
//   - ~3 input vregs for vle32.v operands (KW-wide load in inner loop)
//   - filter weights live in scalar FP regs (ft0..ft11, fa0..fa7)
//   Total vregs in use: ~19 / 32 -> no spills expected.
//
// Workgroup OW = 112 (full row, divides inner 16 cleanly: 112 = 7 * 16).
// Workgroup OH = 16 kept from baseline for cache working-set balance.
// Reduction: KH=1, KW=1, IC=3 (full IC in one step, matches baseline).
module attributes { transform.with_named_sequence } {

  //===--------------------------------------------------------------===//
  // Codegen strategy: tile + decompose + vectorize + bufferize
  //===--------------------------------------------------------------===//
  transform.named_sequence @conv_strip16_strategy(
      %variant_op: !transform.any_op {transform.consumed}) {

    // Phase 1: match the target conv.
    %conv = transform.structured.match ops{["linalg.conv_2d_nhwc_hwcf"]}
        in %variant_op : (!transform.any_op) -> !transform.any_op

    // Phase 2: workgroup-level distribution (tile_using_forall over the
    // parallel dims OH, OW, OF). Keep OH=16, take full OW=112 row, full OF=32.
    %tiled_wg, %forall_wg = transform.structured.tile_using_forall %conv
        tile_sizes [0, 16, 112, 32, 0, 0, 0]
        ( mapping = [#iree_codegen.workgroup_mapping<z>,
                     #iree_codegen.workgroup_mapping<y>,
                     #iree_codegen.workgroup_mapping<x>] )
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)
    transform.iree.populate_workgroup_count_region_using_num_threads_slice
        %forall_wg : (!transform.any_op) -> ()

    // Phase 3: inner parallel tiling. OW strip = 16 (doubled from baseline 8).
    // N=1, OH row-at-a-time, OW=16 strip, OF=32 (full slab).
    %tiled_inner, %l_n, %l_oh, %l_ow, %l_of =
        transform.structured.tile_using_for %tiled_wg
            tile_sizes [1, 1, 16, 32, 0, 0, 0]
      : (!transform.any_op)
      -> (!transform.any_op,
          !transform.op<"scf.for">, !transform.op<"scf.for">,
          !transform.op<"scf.for">, !transform.op<"scf.for">)

    // Phase 4: reduction tiling. KH=1, KW=1, IC=3 (fully unroll IC).
    %tiled_red, %l_kh, %l_kw, %l_ic =
        transform.structured.tile_using_for %tiled_inner
            tile_sizes [0, 0, 0, 0, 1, 1, 3]
      : (!transform.any_op)
      -> (!transform.any_op,
          !transform.op<"scf.for">, !transform.op<"scf.for">,
          !transform.op<"scf.for">)

    // Phase 5: decompose the now-1x1 conv into matmul-equivalent linalg ops
    // so the vectorizer can lower the window-reduction semantics.
    %decomposed = transform.structured.decompose %tiled_red
      : (!transform.any_op) -> !transform.any_op

    // Phase 6: vectorize. Re-match func after all structural changes.
    %func = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.apply_patterns to %func {
      transform.apply_patterns.iree.fold_reshape_into_tensor_hal_interface
      transform.apply_patterns.linalg.fold_unit_extent_dims_via_slices
      transform.apply_patterns.vector.cast_away_vector_leading_one_dim
    } : !transform.any_op
    %func_v = transform.structured.vectorize_children_and_apply_patterns %func
      : (!transform.any_op) -> !transform.any_op

    // Phase 7: vector lowering (outerproduct -> vfmacc.vf friendly).
    transform.apply_patterns to %func_v {
      transform.apply_patterns.vector.lower_contraction
          lowering_strategy = "outerproduct"
      transform.apply_patterns.vector.lower_multi_reduction
          lowering_strategy = "innerparallel"
      transform.apply_patterns.vector.transfer_permutation_patterns
    } : !transform.any_op

    // Phase 8: bufferize (CPU -- no target_gpu selector).
    transform.apply_patterns to %func_v {
      transform.apply_patterns.iree.fold_fill_into_pad
      transform.apply_patterns.linalg.tiling_canonicalization
      transform.apply_patterns.scf.for_loop_canonicalization
    } : !transform.any_op
    transform.apply_patterns to %func_v {
      transform.apply_patterns.tensor.reassociative_reshape_folding
      transform.apply_patterns.canonicalization
    } : !transform.any_op
    transform.apply_cse to %func_v : !transform.any_op
    transform.iree.eliminate_empty_tensors %variant_op
      : (!transform.any_op) -> ()
    transform.apply_patterns to %func_v {
      transform.apply_patterns.linalg.erase_unnecessary_inputs
    } : !transform.any_op
    %memref_func = transform.iree.bufferize %func_v
      : (!transform.any_op) -> (!transform.any_op)

    // Phase 9: convert workgroup-tagged forall to hal workgroup ids.
    %func_final = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.iree.forall_to_workgroup %func_final
      : (!transform.any_op) -> ()

    // Phase 10 (required): reset translation_info to None so the dispatch
    // pass-through check in LowerExecutableUsingTransformDialect succeeds.
    %none_info = transform.param.constant
        #iree_codegen.translation_info<pipeline = None> -> !transform.any_param
    transform.annotate %func_final "translation_info" = %none_info
      : !transform.any_op, !transform.any_param

    transform.yield
  }

  //===--------------------------------------------------------------===//
  // Matcher: pick the specific conv op
  //===--------------------------------------------------------------===//
  transform.named_sequence @match_target_conv(
      %op: !transform.any_op {transform.readonly}) -> (!transform.any_op) {
    transform.match.operation_name %op ["linalg.conv_2d_nhwc_hwcf"]
      : !transform.any_op
    transform.yield %op : !transform.any_op
  }

  //===--------------------------------------------------------------===//
  // Annotator: wire the strategy to the dispatch's func.func
  //===--------------------------------------------------------------===//
  transform.named_sequence @annotate_target_conv(
      %op: !transform.any_op {transform.readonly}) {
    %variant = transform.get_parent_op %op
        {op_name = "hal.executable.variant"}
      : (!transform.any_op) -> !transform.any_op
    %funcs = transform.structured.match ops{["func.func"]} in %variant
      : (!transform.any_op) -> !transform.any_op
    %info = transform.param.constant
        #iree_codegen.translation_info<
            pipeline = TransformDialectCodegen
            codegen_spec = @conv_strip16_strategy> -> !transform.any_param
    transform.annotate %funcs "translation_info" = %info
      : !transform.any_op, !transform.any_param
    transform.yield
  }

  //===--------------------------------------------------------------===//
  // Entry point: walk the dispatch and attach the strategy
  //===--------------------------------------------------------------===//
  transform.named_sequence @__kernel_config(
      %variant_op: !transform.any_op {transform.consumed})
    -> !transform.any_op {
    %res = transform.foreach_match in %variant_op
        @match_target_conv -> @annotate_target_conv
      : (!transform.any_op) -> !transform.any_op
    transform.yield %res : !transform.any_op
  }
}
